values
('additional-maths:1-1-notation-functions-and-indices:mcq:a22942cf', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'mcq', 'mcq', 1, '{"question": "Simplify \\( a^6 \\times a^4 \\).", "options": ["\\( a^{24} \\)", "\\( a^{10} \\)", "\\( a^{2} \\)", "\\( 2a^{10} \\)"]}'::jsonb, '{"answer": 1, "explain": "Multiplying powers of the same base ADDS the indices: \\( a^{6+4} = a^{10} \\). Multiplying them (\\( a^{24} \\)) is the classic slip."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:mcq:851ac381', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'mcq', 'mcq', 1, '{"question": "Simplify \\( x^9 \\div x^4 \\).", "options": ["\\( x^{13} \\)", "\\( x^{2.25} \\)", "\\( x^{5} \\)", "\\( x^{36} \\)"]}'::jsonb, '{"answer": 2, "explain": "Dividing powers of the same base SUBTRACTS the indices: \\( x^{9-4} = x^{5} \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:mcq:84ea1ff7', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'mcq', 'mcq', 1, '{"question": "Simplify \\( (y^3)^5 \\).", "options": ["\\( y^{8} \\)", "\\( y^{15} \\)", "\\( y^{2} \\)", "\\( y^{35} \\)"]}'::jsonb, '{"answer": 1, "explain": "Power of a power MULTIPLIES the indices: \\( y^{3 \\times 5} = y^{15} \\). Adding them (\\( y^8 \\)) confuses this law with the multiplication law."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:mcq:053ba7d8', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'mcq', 'mcq', 1, '{"question": "Evaluate \\( 7^0 \\).", "options": ["\\( 0 \\)", "\\( 1 \\)", "\\( 7 \\)", "\\( 70 \\)"]}'::jsonb, '{"answer": 1, "explain": "Any non-zero base to the power \\( 0 \\) equals \\( 1 \\), so \\( 7^0 = 1 \\), never \\( 0 \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:mcq:4fc9e79c', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'mcq', 'mcq', 1, '{"question": "Evaluate \\( 2^{-4} \\).", "options": ["\\( -16 \\)", "\\( -8 \\)", "\\( \\frac{1}{16} \\)", "\\( \\frac{1}{8} \\)"]}'::jsonb, '{"answer": 2, "explain": "\\( 2^{-4} = \\dfrac{1}{2^4} = \\dfrac{1}{16} \\). The negative index takes the reciprocal; it does not make the value negative."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:mcq:5e7468e2', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'mcq', 'mcq', 1, '{"question": "Evaluate \\( 16^{1/2} \\).", "options": ["\\( 8 \\)", "\\( 4 \\)", "\\( 32 \\)", "\\( 256 \\)"]}'::jsonb, '{"answer": 1, "explain": "A \\( \\tfrac{1}{2} \\) index means the square root: \\( 16^{1/2} = \\sqrt{16} = 4 \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:mcq:df6e2d55', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'mcq', 'mcq', 1, '{"question": "Evaluate \\( 8^{2/3} \\).", "options": ["\\( \\frac{16}{3} \\)", "\\( 4 \\)", "\\( 16 \\)", "\\( 32 \\)"]}'::jsonb, '{"answer": 1, "explain": "\\( 8^{2/3} = \\left(\\sqrt[3]{8}\\right)^2 = 2^2 = 4 \\). Multiplying \\( 8 \\times \\tfrac{2}{3} = \\tfrac{16}{3} \\) treats the index as a multiplier — a common error."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:mcq:c290522f', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'mcq', 'mcq', 1, '{"question": "Evaluate \\( 25^{-1/2} \\).", "options": ["\\( -5 \\)", "\\( \\frac{1}{5} \\)", "\\( 5 \\)", "\\( -\\frac{1}{5} \\)"]}'::jsonb, '{"answer": 1, "explain": "The half roots it and the minus reciprocates it: \\( 25^{-1/2} = \\dfrac{1}{\\sqrt{25}} = \\dfrac{1}{5} \\), which is positive."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:mcq:a7ca53bb', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'mcq', 'mcq', 1, '{"question": "In the expression \\( 9 - 4x^3 \\), what is the coefficient of \\( x^3 \\)?", "options": ["\\( -4 \\)", "\\( 4 \\)", "\\( 3 \\)", "\\( 9 \\)"]}'::jsonb, '{"answer": 0, "explain": "The coefficient is the number multiplying \\( x^3 \\), including its sign: \\( -4 \\). The \\( 3 \\) is the index and \\( 9 \\) is a constant."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:mcq:322a5e3e', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'mcq', 'mcq', 1, '{"question": "Given \\( \\text{f}(x) = 3x - 4 \\), find \\( \\text{f}(2) \\).", "options": ["\\( 2 \\)", "\\( 10 \\)", "\\( 6 \\)", "\\( 1 \\)"]}'::jsonb, '{"answer": 0, "explain": "Substitute \\( x = 2 \\): \\( 3(2) - 4 = 6 - 4 = 2 \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:mcq:83505b3f', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'mcq', 'mcq', 1, '{"question": "Given \\( \\text{f}(x) = x^2 - 4x \\), find \\( \\text{f}(-1) \\).", "options": ["\\( -3 \\)", "\\( 5 \\)", "\\( -5 \\)", "\\( 3 \\)"]}'::jsonb, '{"answer": 1, "explain": "\\( \\text{f}(-1) = (-1)^2 - 4(-1) = 1 + 4 = 5 \\). The square is positive and subtracting \\( -4(-1) \\) adds \\( 4 \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:mcq:decebf65', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'mcq', 'mcq', 1, '{"question": "Simplify \\( (2x^2)^3 \\).", "options": ["\\( 2x^6 \\)", "\\( 6x^6 \\)", "\\( 8x^5 \\)", "\\( 8x^6 \\)"]}'::jsonb, '{"answer": 3, "explain": "Cube both parts: \\( 2^3 = 8 \\) and \\( (x^2)^3 = x^{6} \\), giving \\( 8x^6 \\). Forgetting to cube the \\( 2 \\) gives \\( 2x^6 \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:tf:f7c29f2d', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'tf', 'tf', 1, '{"question": "\\( a^m \\times a^n = a^{m+n} \\)."}'::jsonb, '{"answer": true, "explain": "Multiplying powers of the same base adds the indices — this is the first index law."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:tf:24226a6f', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'tf', 'tf', 1, '{"question": "\\( a^0 = 0 \\) for every base \\( a \\)."}'::jsonb, '{"answer": false, "explain": "Any non-zero base to the power \\( 0 \\) equals \\( 1 \\), not \\( 0 \\): \\( a^0 = 1 \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:tf:ce26623f', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'tf', 'tf', 1, '{"question": "\\( (a^m)^n = a^{m+n} \\)."}'::jsonb, '{"answer": false, "explain": "Power of a power MULTIPLIES the indices: \\( (a^m)^n = a^{mn} \\). Adding them confuses this with the multiplication law."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:tf:c3d4e589', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'tf', 'tf', 1, '{"question": "\\( a^{-n} = \\frac{1}{a^{n}} \\)."}'::jsonb, '{"answer": true, "explain": "A negative index means take the reciprocal; the result is a fraction, not a negative number."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:tf:0a139521', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'tf', 'tf', 1, '{"question": "\\( a^{1/2} = \\sqrt{a} \\)."}'::jsonb, '{"answer": true, "explain": "An index of \\( \\tfrac{1}{2} \\) is the square root; more generally \\( a^{1/n} = \\sqrt[n]{a} \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:tf:05587189', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'tf', 'tf', 1, '{"question": "In \\( 5x^3 \\) the coefficient is \\( 3 \\)."}'::jsonb, '{"answer": false, "explain": "The coefficient is the number multiplying the variable, so it is \\( 5 \\). The \\( 3 \\) is the index (power)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:tf:1d5f443c', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'tf', 'tf', 1, '{"question": "An identity (written with \\( \\equiv \\)) is true for every value of the variable."}'::jsonb, '{"answer": true, "explain": "That is exactly what \\( \\equiv \\) signals, e.g. \\( (x+1)^2 \\equiv x^2 + 2x + 1 \\) holds for all \\( x \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:tf:90bb5b1d', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'tf', 'tf', 1, '{"question": "\\( 8^{2/3} = \\frac{16}{3} \\)."}'::jsonb, '{"answer": false, "explain": "\\( 8^{2/3} = \\left(\\sqrt[3]{8}\\right)^2 = 2^2 = 4 \\). Multiplying \\( 8 \\times \\tfrac{2}{3} \\) treats the index as a multiplier — wrong."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:learn:da03be96', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'learn', 'mcq', 1, '{"readingTitle": "What do the words constant, coefficient, term and variable mean?", "reading": "<p>Algebra has a precise vocabulary. Using it correctly is a real exam skill — mark schemes and command words are written in it.</p>\n            <ul>\n              <li>A <strong>variable</strong> (or <strong>unknown</strong>) is a letter standing for a quantity, e.g. \\( x \\). We call it a <em>variable</em> when its value may change, and an <em>unknown</em> when we are solving to find its one value.</li>\n              <li>A <strong>constant</strong> is a fixed number, e.g. the \\( 7 \\) in \\( 3x + 7 \\).</li>\n              <li>A <strong>term</strong> is a single part of an expression separated by \\( + \\) or \\( - \\): \\( 3x^2 \\), \\( -5x \\) and \\( 7 \\) are the three terms of \\( 3x^2 - 5x + 7 \\).</li>\n              <li>A <strong>coefficient</strong> is the number multiplying a variable. In \\( -5x \\) the coefficient is \\( -5 \\) (the sign belongs to it).</li>\n              <li>An <strong>expression</strong> is a collection of terms with no equals sign, e.g. \\( 3x^2 - 5x + 7 \\).</li>\n            </ul>\n            <p>An expression has no equals sign; the moment you write \\( = \\) you have an <strong>equation</strong> (next card).</p>", "question": "In the expression \\( 4 - 6x^2 \\), what is the coefficient of \\( x^2 \\)?", "options": ["\\( 4 \\)", "\\( 2 \\)", "\\( -6 \\)", "\\( 6 \\)"]}'::jsonb, '{"answer": 2, "explain": "The coefficient is the number multiplying \\( x^2 \\), including its sign: \\( -6 \\). The \\( 4 \\) is a constant and \\( 2 \\) is the index."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:learn:d7e6f198', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'learn', 'mcq', 1, '{"readingTitle": "What is the difference between an equation and an identity?", "reading": "<p>Both use an equals-type sign, but they mean different things.</p>\n            <ul>\n              <li>An <strong>equation</strong> is true only for particular value(s) of the variable. \\( 2x + 1 = 7 \\) is true <em>only</em> when \\( x = 3 \\); you <em>solve</em> it.</li>\n              <li>An <strong>identity</strong> is true for <em>every</em> value of the variable. We use the sign \\( \\equiv \\) to signal this: \\[ (x + 1)^2 \\equiv x^2 + 2x + 1. \\] Whatever number you put in for \\( x \\), both sides are equal.</li>\n            </ul>\n            <p>Index laws (later cards) are identities: \\( a^m \\times a^n \\equiv a^{m+n} \\) holds for all valid \\( a, m, n \\). You will meet \\( \\equiv \\) when a question asks you to prove or \"show that\" two expressions are the same.</p>", "question": "Which statement is an identity (true for all values of \\( x \\))?", "options": ["\\( 3x = 12 \\)", "\\( x^2 = 9 \\)", "\\( 2(x + 3) \\equiv 2x + 6 \\)", "\\( x + 1 = 0 \\)"]}'::jsonb, '{"answer": 2, "explain": "\\( 2(x+3) \\) expands to \\( 2x+6 \\) for every \\( x \\), so it is an identity. The others are true only for particular values of \\( x \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:learn:d6a3b85b', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'learn', 'mcq', 1, '{"readingTitle": "How do you use function notation f(x)?", "reading": "<p><strong>Function notation</strong> \\( \\text{f}(x) \\) names a rule: it reads \"f of \\( x \\)\" and tells you what to do to the input \\( x \\). To <strong>evaluate</strong> \\( \\text{f}(3) \\), substitute \\( 3 \\) for every \\( x \\).</p>\n            <p><strong>Worked example — given \\( \\text{f}(x) = 2x^2 - 5x + 1 \\), find \\( \\text{f}(3) \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Replace every \\( x \\) with \\( 3 \\): \\( \\text{f}(3) = 2(3)^2 - 5(3) + 1 \\).</td></tr>\n              <tr><td>2. Powers first: \\( (3)^2 = 9 \\), so \\( 2 \\times 9 = 18 \\).</td></tr>\n              <tr><td>3. Then \\( -5 \\times 3 = -15 \\).</td></tr>\n              <tr><td>4. Add up: \\( 18 - 15 + 1 = 4 \\), so \\[ \\text{f}(3) = 4. \\]</td></tr>\n            </table>\n            <p>Watch negatives: \\( \\text{f}(-2) = 2(-2)^2 - 5(-2) + 1 = 8 + 10 + 1 = 19 \\). A squared negative is positive, and subtracting a negative adds.</p>", "question": "If \\( \\text{f}(x) = x^2 + 2 \\), what is \\( \\text{f}(-3) \\)?", "options": ["\\( 11 \\)", "\\( -7 \\)", "\\( -3 \\)", "\\( -9 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\text{f}(-3) = (-3)^2 + 2 = 9 + 2 = 11 \\). A negative squared is positive, so it is \\( +9 \\), not \\( -9 \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:learn:95e2046d', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'learn', 'mcq', 1, '{"readingTitle": "What are the three main index laws?", "reading": "<p>An <strong>index</strong> (or <strong>power</strong>) tells you how many times to multiply the <strong>base</strong> by itself: \\( a^4 = a \\times a \\times a \\times a \\). Three laws let you combine powers of the <em>same base</em>.</p>\n            <table class=\"worked\">\n              <tr><td><strong>Multiplying</strong> — <em>add</em> the indices: \\[ a^m \\times a^n = a^{m+n}. \\] e.g. \\( 2^3 \\times 2^4 = 2^{7} = 128 \\).</td></tr>\n              <tr><td><strong>Dividing</strong> — <em>subtract</em> the indices: \\[ a^m \\div a^n = a^{m-n}. \\] e.g. \\( x^7 \\div x^2 = x^{5} \\).</td></tr>\n              <tr><td><strong>Power of a power</strong> — <em>multiply</em> the indices: \\[ (a^m)^n = a^{mn}. \\] e.g. \\( (y^3)^4 = y^{12} \\).</td></tr>\n            </table>\n            <p><strong>Careful:</strong> the laws only work for the <em>same base</em>. \\( 2^3 \\times 5^2 \\) does <strong>not</strong> simplify by adding indices. When a coefficient is involved, deal with it separately: \\( (2x^3)^2 = 2^2 \\times x^{3 \\times 2} = 4x^6 \\).</p>", "question": "Simplify \\( a^5 \\times a^3 \\).", "options": ["\\( a^{15} \\)", "\\( a^8 \\)", "\\( a^2 \\)", "\\( 2a^8 \\)"]}'::jsonb, '{"answer": 1, "explain": "Multiplying powers of the same base means you ADD the indices: \\( a^{5+3} = a^8 \\). Multiplying the indices (\\( a^{15} \\)) is the classic error."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:learn:573f49bd', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'learn', 'mcq', 1, '{"readingTitle": "What do a zero index and a negative index mean?", "reading": "<p>These two rules follow directly from the division law.</p>\n            <ul>\n              <li><strong>Zero index:</strong> \\( a^m \\div a^m = a^{0} \\), but anything divided by itself is \\( 1 \\), so \\[ a^0 = 1 \\quad (a \\neq 0). \\] Every non-zero base to the power zero is \\( 1 \\) — not \\( 0 \\).</li>\n              <li><strong>Negative index:</strong> a minus sign in the index means \"take the <strong>reciprocal</strong>\": \\[ a^{-n} = \\frac{1}{a^{n}}. \\] It does <em>not</em> make the answer negative.</li>\n            </ul>\n            <p><strong>Worked example — evaluate \\( 2^{-3} \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. The negative index means take the reciprocal: \\( 2^{-3} = \\dfrac{1}{2^{3}} \\).</td></tr>\n              <tr><td>2. Work out the positive power: \\( 2^3 = 8 \\).</td></tr>\n              <tr><td>3. So \\[ 2^{-3} = \\frac{1}{8}. \\]</td></tr>\n            </table>\n            <p>The answer \\( \\tfrac{1}{8} \\) is positive — a negative index never means a negative number.</p>", "question": "Evaluate \\( 5^{-2} \\).", "options": ["\\( -25 \\)", "\\( -10 \\)", "\\( \\frac{1}{25} \\)", "\\( \\frac{1}{10} \\)"]}'::jsonb, '{"answer": 2, "explain": "\\( 5^{-2} = \\dfrac{1}{5^2} = \\dfrac{1}{25} \\). The negative index takes the reciprocal; the result stays positive."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:learn:035b7906', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'learn', 'mcq', 1, '{"readingTitle": "How do you evaluate a fractional index like 8^(2/3)?", "reading": "<p>A fractional index combines a root and a power.</p>\n            <ul>\n              <li>The <strong>denominator is a root</strong>: \\( a^{1/n} = \\sqrt[n]{a} \\). So \\( a^{1/2} = \\sqrt{a} \\) and \\( a^{1/3} = \\sqrt[3]{a} \\).</li>\n              <li>The <strong>numerator is a power</strong>: \\[ a^{m/n} = \\left(\\sqrt[n]{a}\\right)^{m} = \\sqrt[n]{a^{m}}. \\]</li>\n            </ul>\n            <p>Take the root <em>first</em> — the numbers stay small and it is easier by hand.</p>\n            <p><strong>Worked example — evaluate \\( 8^{2/3} \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Denominator \\( 3 \\) is the root: \\( \\sqrt[3]{8} = 2 \\).</td></tr>\n              <tr><td>2. Numerator \\( 2 \\) is the power: \\( 2^{2} = 4 \\).</td></tr>\n              <tr><td>3. So \\[ 8^{2/3} = \\left(\\sqrt[3]{8}\\right)^{2} = 2^{2} = 4. \\]</td></tr>\n            </table>\n            <p>Combine with a negative index too: \\( 16^{-1/2} = \\dfrac{1}{16^{1/2}} = \\dfrac{1}{\\sqrt{16}} = \\dfrac{1}{4} \\). The minus flips it, the half roots it.</p>", "question": "Evaluate \\( 27^{2/3} \\).", "options": ["\\( 9 \\)", "\\( 18 \\)", "\\( 3 \\)", "\\( 729 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\sqrt[3]{27} = 3 \\), then \\( 3^2 = 9 \\). Root first, then power."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:learn:f6f331d0', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'learn', 'mcq', 1, '{"readingTitle": "Which formulae must you memorise here?", "reading": "<p>The <strong>index laws are MEMORISE material</strong> — they are <em>not</em> on the exam formula sheet. Learn all seven as identities you can recall instantly:</p>\n            <table class=\"worked\">\n              <tr><td>\\( a^m \\times a^n = a^{m+n} \\)</td><td>\\( a^m \\div a^n = a^{m-n} \\)</td></tr>\n              <tr><td>\\( (a^m)^n = a^{mn} \\)</td><td>\\( a^0 = 1 \\)</td></tr>\n              <tr><td>\\( a^{-n} = \\dfrac{1}{a^{n}} \\)</td><td>\\( a^{1/n} = \\sqrt[n]{a} \\)</td></tr>\n              <tr><td colspan=\"2\">\\( a^{m/n} = \\left(\\sqrt[n]{a}\\right)^{m} \\)</td></tr>\n            </table>\n            <p>Function notation and the vocabulary (constant, coefficient, identity \\( \\equiv \\), variable) also carry no formula-sheet support — they are assumed knowledge used throughout the whole paper. This first lesson is the toolkit every later topic relies on, so fluency here pays off everywhere.</p>", "question": "Which of these is TRUE for every non-zero base \\( a \\)?", "options": ["\\( a^0 = 0 \\)", "\\( a^0 = 1 \\)", "\\( a^0 = a \\)", "\\( a^0 = -1 \\)"]}'::jsonb, '{"answer": 1, "explain": "Any non-zero number raised to the power \\( 0 \\) equals \\( 1 \\); this follows from \\( a^m \\div a^m = a^0 = 1 \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:misc:5471fb24', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( a^0 = 0 \\)</p><p><strong>✅ The correct idea:</strong> Any non-zero base to the power zero is \\( 1 \\). A weak answer copies the \\( 0 \\); a strong answer recalls \\( a^m \\div a^m = a^0 = 1 \\).</p>", "question": "Evaluate \\( 12^0 \\).", "options": ["\\( 1 \\)", "\\( 0 \\)", "\\( 12 \\)", "\\( 120 \\)"]}'::jsonb, '{"answer": 0, "explain": "Every non-zero base to the power \\( 0 \\) is \\( 1 \\), so \\( 12^0 = 1 \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:misc:bfdf4a1a', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( a^m \\times a^n = a^{mn} \\) (multiply the indices)</p><p><strong>✅ The correct idea:</strong> Multiplying powers of the same base ADDS the indices. A weak answer multiplies; a strong answer writes \\( a^m \\times a^n = a^{m+n} \\), keeping the power-of-a-power rule separate.</p>", "question": "Simplify \\( x^2 \\times x^5 \\).", "options": ["\\( x^{7} \\)", "\\( x^{10} \\)", "\\( x^{3} \\)", "\\( x^{25} \\)"]}'::jsonb, '{"answer": 0, "explain": "Add the indices: \\( x^{2+5} = x^7 \\). \\( x^{10} \\) comes from wrongly multiplying them."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:misc:6ceb1a34', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( (a^m)^n = a^{m+n} \\) (add the indices)</p><p><strong>✅ The correct idea:</strong> Power of a power MULTIPLIES the indices. A weak answer adds; a strong answer writes \\( (a^m)^n = a^{mn} \\).</p>", "question": "Simplify \\( (x^4)^2 \\).", "options": ["\\( x^{8} \\)", "\\( x^{6} \\)", "\\( x^{2} \\)", "\\( x^{16} \\)"]}'::jsonb, '{"answer": 0, "explain": "Multiply the indices: \\( x^{4 \\times 2} = x^8 \\). Adding them gives the wrong \\( x^6 \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:misc:4f2a277b', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( 2^{-3} = -8 \\) (a negative index gives a negative answer)</p><p><strong>✅ The correct idea:</strong> A negative index means the reciprocal, not a negative value. A weak answer negates; a strong answer writes \\( 2^{-3} = \\dfrac{1}{2^3} = \\dfrac{1}{8} \\).</p>", "question": "Evaluate \\( 3^{-2} \\).", "options": ["\\( \\frac{1}{9} \\)", "\\( -9 \\)", "\\( -6 \\)", "\\( 9 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( 3^{-2} = \\dfrac{1}{3^2} = \\dfrac{1}{9} \\); the answer is positive."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:misc:b3e80491', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( 8^{2/3} = 8 \\times \\frac{2}{3} = \\frac{16}{3} \\)</p><p><strong>✅ The correct idea:</strong> A fractional index is a root and a power, not a multiplier. A weak answer multiplies the base by the fraction; a strong answer takes the root first: \\( \\left(\\sqrt[3]{8}\\right)^2 = 2^2 = 4 \\).</p>", "question": "Evaluate \\( 4^{3/2} \\).", "options": ["\\( 8 \\)", "\\( 6 \\)", "\\( \\frac{3}{2} \\)", "\\( 64 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\sqrt{4} = 2 \\), then \\( 2^3 = 8 \\). Root first, then power."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:misc:9408fc06', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> In \\( 6x^2 \\) the coefficient is \\( 2 \\)</p><p><strong>✅ The correct idea:</strong> The coefficient is the number multiplying the variable, so it is \\( 6 \\). A weak answer names the index; a strong answer distinguishes coefficient (\\( 6 \\)) from index (\\( 2 \\)).</p>", "question": "What is the coefficient of \\( x \\) in \\( -7x \\)?", "options": ["\\( -7 \\)", "\\( 7 \\)", "\\( 1 \\)", "\\( x \\)"]}'::jsonb, '{"answer": 0, "explain": "The coefficient includes its sign, so it is \\( -7 \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:tips:7040124b', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'tips', 'mcq', 1, '{"readingTitle": "explain — Read the command word: Simplify vs Evaluate", "reading": "<p><strong>Simplify</strong> means combine into one power/term but leave letters in: \\( a^5 \\times a^3 \\to a^8 \\). <strong>Evaluate</strong> (or \"work out\") means give a single number: \\( 8^{2/3} \\to 4 \\). <strong>Write down / state</strong> means no working is expected — just the answer. Giving a decimal when a simplified power was asked for, or an unfinished power when a number was asked for, both lose marks.</p>", "question": "\"Evaluate \\( 16^{1/2} \\)\" is asking you to:", "options": ["Give a single number", "Leave it as a power", "Draw a graph", "Round to 3 s.f. only"]}'::jsonb, '{"answer": 0, "explain": "''Evaluate'' wants a numerical value: \\( \\sqrt{16} = 4 \\)."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:tips:6f20c0ea', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'tips', 'mcq', 1, '{"readingTitle": "tip — Show your working on fractional indices", "reading": "<p><strong>0 marks:</strong> \\( 27^{2/3} = 18 \\) (multiplied \\( 27 \\times \\tfrac{2}{3} \\)) — a wrong single number with no method shown. <strong>Partial:</strong> writes \\( \\sqrt[3]{27} = 3 \\) then stops. <strong>Full marks:</strong> \\( \\sqrt[3]{27} = 3 \\), then \\( 3^2 = 9 \\). Show the root step and the power step so a slip costs one mark, not all of them.</p>", "question": "Why write out both the root step and the power step?", "options": ["To earn method marks even if the final value slips", "It wastes time", "To use more paper", "It is never needed"]}'::jsonb, '{"answer": 0, "explain": "Splitting a fractional index into its root and power shows method, protecting the marks if one step slips."}'::jsonb),
('additional-maths:1-1-notation-functions-and-indices:tips:755cb438', 'additional-maths', 'additional-maths:1-1-notation-functions-and-indices', '1.1 Notation, Functions and Indices', 'tips', 'mcq', 1, '{"readingTitle": "explain — Index laws are MEMORISE, not on the sheet", "reading": "<p>The index laws are <strong>not</strong> printed on the exam formula sheet — you must recall them. A frequent slip is applying a law across <em>different</em> bases: \\( 2^3 \\times 5^2 \\) cannot be combined by adding indices because the bases differ. Only same-base powers combine.</p>", "question": "Which product can be simplified by adding indices?", "options": ["\\( 3^4 \\times 3^2 \\)", "\\( 3^4 \\times 5^2 \\)", "\\( 2^4 \\times 7^4 \\)", "\\( 3^4 + 3^2 \\)"]}'::jsonb, '{"answer": 0, "explain": "Only \\( 3^4 \\times 3^2 \\) shares a base, giving \\( 3^6 \\). Different bases cannot be combined this way."}'::jsonb),
