('additional-maths:1-2-surds-and-algebraic-fractions:mcq:6a8e5905', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'mcq', 'mcq', 1, '{"question": "Rationalise \\( \\dfrac{1}{\\sqrt{3}} \\).", "options": ["\\( \\dfrac{\\sqrt{3}}{3} \\)", "\\( \\dfrac{1}{3} \\)", "\\( \\sqrt{3} \\)", "\\( \\dfrac{3}{\\sqrt{3}} \\)"]}'::jsonb, '{"answer": 0, "explain": "Multiply top and bottom by \\( \\sqrt{3} \\): \\( \\dfrac{\\sqrt{3}}{\\sqrt{3}\\,\\sqrt{3}} = \\dfrac{\\sqrt{3}}{3} \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:mcq:5a9dd9a9', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'mcq', 'mcq', 1, '{"question": "Rationalise \\( \\dfrac{6}{\\sqrt{2}} \\).", "options": ["\\( 3\\sqrt{2} \\)", "\\( 6\\sqrt{2} \\)", "\\( 3 \\)", "\\( \\sqrt{3} \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\dfrac{6}{\\sqrt{2}} \\times \\dfrac{\\sqrt{2}}{\\sqrt{2}} = \\dfrac{6\\sqrt{2}}{2} = 3\\sqrt{2} \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:mcq:d2285024', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'mcq', 'mcq', 1, '{"question": "To rationalise \\( \\dfrac{1}{2 + \\sqrt{3}} \\) you multiply top and bottom by:", "options": ["\\( 2 - \\sqrt{3} \\)", "\\( 2 + \\sqrt{3} \\)", "\\( \\sqrt{3} \\)", "\\( \\dfrac{1}{2 - \\sqrt{3}} \\)"]}'::jsonb, '{"answer": 0, "explain": "The conjugate \\( 2 - \\sqrt{3} \\) makes the denominator \\( 4 - 3 = 1 \\), clearing the surd."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:mcq:584e950e', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'mcq', 'mcq', 1, '{"question": "Rationalise \\( \\dfrac{1}{2 + \\sqrt{3}} \\) fully.", "options": ["\\( 2 - \\sqrt{3} \\)", "\\( \\dfrac{2 - \\sqrt{3}}{7} \\)", "\\( 2 + \\sqrt{3} \\)", "\\( \\dfrac{2 - \\sqrt{3}}{5} \\)"]}'::jsonb, '{"answer": 0, "explain": "Denominator \\( (2+\\sqrt{3})(2-\\sqrt{3}) = 4 - 3 = 1 \\), so the answer is \\( 2 - \\sqrt{3} \\). Using \\( 4 + 3 = 7 \\) is the classic sign error."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:mcq:b4924cb9', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'mcq', 'mcq', 1, '{"question": "Simplify \\( \\dfrac{x^2 - 9}{x + 3} \\).", "options": ["\\( x - 3 \\)", "\\( x + 3 \\)", "\\( x - 9 \\)", "\\( x^2 - 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "Factorise \\( x^2 - 9 = (x+3)(x-3) \\) then cancel \\( (x+3) \\) to get \\( x - 3 \\). You cannot cancel the \\( 9 \\) on its own."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:mcq:336ae9df', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'mcq', 'mcq', 1, '{"question": "Simplify \\( \\dfrac{x^2 + 5x + 6}{x^2 - 4} \\).", "options": ["\\( \\dfrac{x+3}{x-2} \\)", "\\( \\dfrac{x+3}{x+2} \\)", "\\( \\dfrac{5x+6}{-4} \\)", "\\( x + 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\dfrac{(x+2)(x+3)}{(x+2)(x-2)} \\); cancel \\( (x+2) \\) to get \\( \\dfrac{x+3}{x-2} \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:mcq:6055d1db', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'mcq', 'mcq', 1, '{"question": "Simplify \\( \\dfrac{1}{x-1} - \\dfrac{2}{x+1} \\).", "options": ["\\( \\dfrac{3 - x}{(x-1)(x+1)} \\)", "\\( \\dfrac{-x - 1}{(x-1)(x+1)} \\)", "\\( \\dfrac{3 - x}{x-1} \\)", "\\( \\dfrac{-1}{(x-1)(x+1)} \\)"]}'::jsonb, '{"answer": 0, "explain": "Numerator \\( (x+1) - 2(x-1) = x + 1 - 2x + 2 = 3 - x \\). The option \\( -x-1 \\) comes from writing \\( -2(x-1) = -2x - 2 \\) — a sign error."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:tf:4fcf4f41', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'tf', 'tf', 1, '{"question": "\\( \\sqrt{50} = 5\\sqrt{2} \\)."}'::jsonb, '{"answer": true, "explain": "\\( 50 = 25 \\times 2 \\), so \\( \\sqrt{50} = \\sqrt{25}\\,\\sqrt{2} = 5\\sqrt{2} \\). ✓"}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:tf:bebd729a', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'tf', 'tf', 1, '{"question": "\\( \\sqrt{12} + \\sqrt{3} = \\sqrt{15} \\)."}'::jsonb, '{"answer": false, "explain": "You cannot add the numbers under the root. \\( \\sqrt{12} = 2\\sqrt{3} \\), so \\( 2\\sqrt{3} + \\sqrt{3} = 3\\sqrt{3} \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:tf:20d04a9e', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'tf', 'tf', 1, '{"question": "Rationalising \\( \\dfrac{5}{\\sqrt{5}} \\) gives \\( \\sqrt{5} \\)."}'::jsonb, '{"answer": true, "explain": "\\( \\dfrac{5}{\\sqrt{5}} \\times \\dfrac{\\sqrt{5}}{\\sqrt{5}} = \\dfrac{5\\sqrt{5}}{5} = \\sqrt{5} \\). ✓"}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:tf:fdc492f4', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'tf', 'tf', 1, '{"question": "\\( (\\sqrt{7} - 2)(\\sqrt{7} + 2) = 3 \\)."}'::jsonb, '{"answer": true, "explain": "Difference of two squares: \\( (\\sqrt{7})^2 - 2^2 = 7 - 4 = 3 \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:tf:52ebf0f7', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'tf', 'tf', 1, '{"question": "\\( \\dfrac{1}{3 - \\sqrt{2}} = \\dfrac{3 + \\sqrt{2}}{7} \\)."}'::jsonb, '{"answer": true, "explain": "Multiply by the conjugate \\( 3+\\sqrt{2} \\): denominator \\( 9 - 2 = 7 \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:tf:76f0899e', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'tf', 'tf', 1, '{"question": "\\( \\dfrac{x^2 - 9}{x + 3} \\) simplifies to \\( x - 9 \\) by cancelling the \\( x^2 \\) and the \\( 9 \\)."}'::jsonb, '{"answer": false, "explain": "You may only cancel factors. Factorise first: \\( \\dfrac{(x+3)(x-3)}{x+3} = x - 3 \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:tf:c7f09e72', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'tf', 'tf', 1, '{"question": "To add \\( \\dfrac{1}{x-1} \\) and \\( \\dfrac{2}{x+1} \\) you use the common denominator \\( (x-1)(x+1) \\)."}'::jsonb, '{"answer": true, "explain": "Each fraction is rewritten over \\( (x-1)(x+1) \\) before the numerators are combined."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:tf:a170e857', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'tf', 'tf', 1, '{"question": "On a ''detailed reasoning'' question, a correct answer straight from a calculator earns full marks."}'::jsonb, '{"answer": false, "explain": "DR requires the complete method to be written out; an unexplained calculator answer scores 0 even when correct."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:learn:1239c2d9', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'learn', 'mcq', 1, '{"readingTitle": "How do you simplify a surd?", "reading": "<p>A <strong>surd</strong> is a root that cannot be written as an exact rational number, such as \\( \\sqrt{3} \\) or \\( \\sqrt{12} \\). You <strong>simplify</strong> a surd by taking out the largest <strong>perfect-square factor</strong>.</p>\n            <ul>\n              <li>Use the rule \\( \\sqrt{ab} = \\sqrt{a}\\,\\sqrt{b} \\), choosing \\( a \\) to be the biggest square that divides the number.</li>\n              <li>A surd is in simplest form when the number left under the root has <strong>no square factor</strong> bigger than 1.</li>\n            </ul>\n            <p><strong>Worked example — simplify \\( \\sqrt{12} \\) and \\( \\sqrt{125} \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. \\( 12 = 4 \\times 3 \\), and \\( 4 \\) is the largest square factor.</td></tr>\n              <tr><td>2. \\( \\sqrt{12} = \\sqrt{4}\\,\\sqrt{3} = 2\\sqrt{3} \\).</td></tr>\n              <tr><td>3. \\( 125 = 25 \\times 5 \\), and \\( 25 \\) is a square factor.</td></tr>\n              <tr><td>4. \\( \\sqrt{125} = \\sqrt{25}\\,\\sqrt{5} = 5\\sqrt{5} \\).</td></tr>\n            </table>\n            <p>Always look for the <em>largest</em> square factor — using \\( \\sqrt{12} = \\sqrt{2}\\,\\sqrt{6} \\) does not finish the job.</p>", "question": "Simplify \\( \\sqrt{200} \\).", "options": ["\\( 10\\sqrt{2} \\)", "\\( 2\\sqrt{50} \\)", "\\( 100\\sqrt{2} \\)", "\\( 20\\sqrt{2} \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( 200 = 100 \\times 2 \\), so \\( \\sqrt{200} = \\sqrt{100}\\,\\sqrt{2} = 10\\sqrt{2} \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:learn:b7d8f5af', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'learn', 'mcq', 1, '{"readingTitle": "How do you add, subtract and multiply surds?", "reading": "<p>You can only add or subtract <strong>like surds</strong> — surds with the same number under the root. Simplify first so the like surds appear.</p>\n            <p><strong>Worked example — \\( \\sqrt{12} + \\sqrt{27} \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. \\( \\sqrt{12} = 2\\sqrt{3} \\) and \\( \\sqrt{27} = \\sqrt{9}\\,\\sqrt{3} = 3\\sqrt{3} \\).</td></tr>\n              <tr><td>2. Both are multiples of \\( \\sqrt{3} \\): \\( 2\\sqrt{3} + 3\\sqrt{3} = 5\\sqrt{3} \\).</td></tr>\n            </table>\n            <p>To <strong>multiply</strong> surds use \\( \\sqrt{a}\\,\\sqrt{b} = \\sqrt{ab} \\); for example \\( \\sqrt{3}\\times\\sqrt{12} = \\sqrt{36} = 6 \\). To <strong>expand brackets</strong>, multiply out as usual and collect like surds.</p>\n            <p><strong>Worked example — expand \\( (3 + \\sqrt{2})^2 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. \\( (3+\\sqrt{2})^2 = (3+\\sqrt{2})(3+\\sqrt{2}) \\).</td></tr>\n              <tr><td>2. \\( = 9 + 3\\sqrt{2} + 3\\sqrt{2} + \\sqrt{2}\\,\\sqrt{2} \\).</td></tr>\n              <tr><td>3. \\( \\sqrt{2}\\,\\sqrt{2} = 2 \\), so \\( = 9 + 6\\sqrt{2} + 2 = 11 + 6\\sqrt{2} \\).</td></tr>\n            </table>\n            <p><strong>Never</strong> write \\( \\sqrt{a} + \\sqrt{b} = \\sqrt{a+b} \\): that is false (\\( \\sqrt{9}+\\sqrt{16} = 7 \\), not \\( \\sqrt{25} = 5 \\)).</p>", "question": "Simplify \\( \\sqrt{50} - \\sqrt{8} \\).", "options": ["\\( 3\\sqrt{2} \\)", "\\( \\sqrt{42} \\)", "\\( 2\\sqrt{2} \\)", "\\( 42\\sqrt{2} \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\sqrt{50} = 5\\sqrt{2} \\) and \\( \\sqrt{8} = 2\\sqrt{2} \\), so \\( 5\\sqrt{2} - 2\\sqrt{2} = 3\\sqrt{2} \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:learn:c7ebe020', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'learn', 'mcq', 1, '{"readingTitle": "How do you rationalise a denominator?", "reading": "<p><strong>Rationalising</strong> means clearing the surd out of the denominator. The trick is to multiply the fraction by a clever form of 1.</p>\n            <p><strong>Simple case</strong> — for \\( \\frac{1}{\\sqrt{3}} \\), multiply top and bottom by \\( \\sqrt{3} \\):</p>\n            <p>\\[ \\frac{1}{\\sqrt{3}} \\times \\frac{\\sqrt{3}}{\\sqrt{3}} = \\frac{\\sqrt{3}}{3}. \\]</p>\n            <p><strong>Conjugate case</strong> — for \\( \\frac{1}{2+\\sqrt{3}} \\), multiply by the <strong>conjugate</strong> \\( 2-\\sqrt{3} \\). The conjugate flips only the sign of the surd, and \\( (a+\\sqrt{b})(a-\\sqrt{b}) = a^2 - b \\) is a whole number (difference of two squares).</p>\n            <table class=\"worked\">\n              <tr><td>1. \\( \\dfrac{1}{2+\\sqrt{3}} \\times \\dfrac{2-\\sqrt{3}}{2-\\sqrt{3}} \\).</td></tr>\n              <tr><td>2. Denominator: \\( (2+\\sqrt{3})(2-\\sqrt{3}) = 4 - 3 = 1 \\).</td></tr>\n              <tr><td>3. So \\( \\dfrac{2-\\sqrt{3}}{1} = 2 - \\sqrt{3} \\).</td></tr>\n            </table>\n            <p>Watch the denominator: it is \\( a^2 - b \\), <em>not</em> \\( a^2 + b \\). For \\( 5 - \\sqrt{2} \\) the conjugate product is \\( 25 - 2 = 23 \\), not 27.</p>", "question": "Rationalise \\( \\frac{1}{3-\\sqrt{2}} \\).", "options": ["\\( \\frac{3+\\sqrt{2}}{7} \\)", "\\( \\frac{3-\\sqrt{2}}{7} \\)", "\\( \\frac{3+\\sqrt{2}}{11} \\)", "\\( 3+\\sqrt{2} \\)"]}'::jsonb, '{"answer": 0, "explain": "Multiply by the conjugate \\( 3+\\sqrt{2} \\): denominator \\( 9 - 2 = 7 \\), giving \\( \\frac{3+\\sqrt{2}}{7} \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:learn:b4924cb9', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'learn', 'mcq', 1, '{"readingTitle": "How do you simplify an algebraic fraction?", "reading": "<p>Simplify an algebraic fraction the same way as a numerical one: <strong>factorise</strong> the numerator and denominator, then <strong>cancel common factors</strong>.</p>\n            <ul>\n              <li>You may only cancel <strong>factors</strong> (things multiplied), never individual <strong>terms</strong> (things added).</li>\n              <li>Common tools: the difference of two squares \\( a^2 - b^2 = (a+b)(a-b) \\), and factorising quadratics.</li>\n            </ul>\n            <p><strong>Worked example — simplify \\( \\dfrac{x^2 + 5x + 6}{x^2 - 4} \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Factorise the top: \\( x^2 + 5x + 6 = (x+2)(x+3) \\).</td></tr>\n              <tr><td>2. Factorise the bottom: \\( x^2 - 4 = (x+2)(x-2) \\).</td></tr>\n              <tr><td>3. Cancel the common factor \\( (x+2) \\): \\( \\dfrac{(x+2)(x+3)}{(x+2)(x-2)} = \\dfrac{x+3}{x-2} \\).</td></tr>\n            </table>\n            <p>You cannot cancel the \\( x \\)''s or the numbers separately — only the whole bracket \\( (x+2) \\).</p>", "question": "Simplify \\( \\dfrac{x^2 - 9}{x + 3} \\).", "options": ["\\( x - 3 \\)", "\\( x + 3 \\)", "\\( x - 9 \\)", "\\( x^2 - 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x^2 - 9 = (x+3)(x-3) \\); cancel \\( (x+3) \\) to leave \\( x - 3 \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:learn:0c39e91b', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'learn', 'mcq', 1, '{"readingTitle": "How do you add and subtract algebraic fractions?", "reading": "<p>Put both fractions over a <strong>common denominator</strong>, combine the numerators, then simplify. The common denominator is usually the two denominators multiplied together.</p>\n            <p><strong>Worked example — \\( \\dfrac{1}{x-1} - \\dfrac{2}{x+1} \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Common denominator \\( (x-1)(x+1) \\).</td></tr>\n              <tr><td>2. Rewrite: \\( \\dfrac{(x+1) - 2(x-1)}{(x-1)(x+1)} \\).</td></tr>\n              <tr><td>3. Expand the numerator: \\( x + 1 - 2x + 2 \\) (the minus multiplies <em>both</em> terms of \\( -2(x-1) \\)).</td></tr>\n              <tr><td>4. Collect: \\( \\dfrac{3 - x}{(x-1)(x+1)} \\).</td></tr>\n            </table>\n            <p>The biggest trap is the <strong>minus sign</strong>: \\( -2(x-1) = -2x + 2 \\), not \\( -2x - 2 \\).</p>", "question": "Simplify \\( \\dfrac{3}{x+2} + \\dfrac{1}{x-1} \\).", "options": ["\\( \\dfrac{4x-1}{(x+2)(x-1)} \\)", "\\( \\dfrac{4x+1}{(x+2)(x-1)} \\)", "\\( \\dfrac{4}{(x+2)(x-1)} \\)", "\\( \\dfrac{3x-1}{(x+2)(x-1)} \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( 3(x-1) + (x+2) = 3x - 3 + x + 2 = 4x - 1 \\), over \\( (x+2)(x-1) \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:learn:bce02b26', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'learn', 'mcq', 1, '{"readingTitle": "How do you multiply and divide algebraic fractions?", "reading": "<p>To <strong>multiply</strong>: factorise everything, cancel any common factor top-to-bottom, then multiply the numerators and the denominators.</p>\n            <p>To <strong>divide</strong>: multiply by the <strong>reciprocal</strong> of the second fraction (flip it), then proceed as for multiplication.</p>\n            <p><strong>Worked example — \\( \\dfrac{x^2 - 1}{x + 2} \\div \\dfrac{x - 1}{x + 2} \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Flip the divisor: \\( \\dfrac{x^2 - 1}{x + 2} \\times \\dfrac{x + 2}{x - 1} \\).</td></tr>\n              <tr><td>2. Factorise: \\( x^2 - 1 = (x+1)(x-1) \\).</td></tr>\n              <tr><td>3. Cancel \\( (x+2) \\) and \\( (x-1) \\): \\( \\dfrac{(x+1)(x-1)(x+2)}{(x+2)(x-1)} = x + 1 \\).</td></tr>\n            </table>\n            <p>Never flip the first fraction — only the one you are <em>dividing by</em>.</p>", "question": "Simplify \\( \\dfrac{x^2 - 1}{x + 2} \\div \\dfrac{x - 1}{x + 2} \\).", "options": ["\\( x + 1 \\)", "\\( x - 1 \\)", "\\( \\dfrac{x+1}{x+2} \\)", "\\( x^2 - 1 \\)"]}'::jsonb, '{"answer": 0, "explain": "Multiply by the reciprocal, factorise \\( x^2-1=(x+1)(x-1) \\), and cancel to get \\( x + 1 \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:learn:b32e1425', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'learn', 'mcq', 1, '{"readingTitle": "What do ''exact'' and ''detailed reasoning'' require?", "reading": "<p>Surd questions almost always carry a command word that controls how you must answer.</p>\n            <ul>\n              <li><strong>''Exact''</strong> means leave the answer in surd or fraction form — \\( \\frac{15+\\sqrt{2}}{23} \\), not \\( 0.696 \\). A decimal-only answer scores no marks.</li>\n              <li><strong>''In this question you must show detailed reasoning'' (DR)</strong> means the full method must be written out. A correct answer taken straight from a calculator scores <strong>zero</strong>, even when it is right.</li>\n            </ul>\n            <p>For a rationalising DR question (like 2023 Q4(b)) you must <em>show</em> the unsimplified numerator over the common denominator before you tidy it up — that visible step is a mark in its own right.</p>", "question": "On a ''detailed reasoning'' surd question, what scores 0 marks?", "options": ["A correct answer with no working (straight from a calculator)", "Showing every algebraic step", "Leaving the answer as a surd", "Writing the common denominator first"]}'::jsonb, '{"answer": 0, "explain": "DR requires the full analytical method; an unexplained calculator answer earns nothing even if correct."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:misc:9d7cc3c3', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( \\dfrac{1}{x-2} - \\dfrac{2}{x+1} = \\dfrac{-x-3}{(x-2)(x+1)} \\)</p><p><strong>✅ The correct idea:</strong> The minus sign must multiply BOTH terms of \\( -2(x-2) = -2x + 4 \\). A weak answer writes \\( -2x - 4 \\) and gets \\( -x - 3 \\); a strong answer gets \\( x + 1 - 2x + 4 = 5 - x \\).</p>", "question": "What is the numerator of \\( \\dfrac{1}{x-2} - \\dfrac{2}{x+1} \\)?", "options": ["\\( 5 - x \\)", "\\( -x - 3 \\)", "\\( -x - 1 \\)", "\\( x - 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (x+1) - 2(x-2) = x + 1 - 2x + 4 = 5 - x \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:misc:f0de010f', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( (5 - \\sqrt{2})(5 + \\sqrt{2}) = 27 \\)</p><p><strong>✅ The correct idea:</strong> This is a difference of two squares: \\( 25 - 2 = 23 \\), not \\( 25 + 2 = 27 \\). A weak answer adds; a strong answer subtracts, giving the denominator 23.</p>", "question": "\\( (5 - \\sqrt{2})(5 + \\sqrt{2}) = \\)", "options": ["\\( 23 \\)", "\\( 27 \\)", "\\( 25 \\)", "\\( 5\\sqrt{2} \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( 5^2 - (\\sqrt{2})^2 = 25 - 2 = 23 \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:misc:b4924cb9', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( \\dfrac{x^2 - 9}{x + 3} = x^2 - 3 \\) by cancelling the \\( x \\)</p><p><strong>✅ The correct idea:</strong> You may only cancel FACTORS, not terms. A weak answer cancels the \\( x \\)''s; a strong answer factorises \\( (x+3)(x-3) \\) and cancels the bracket to get \\( x - 3 \\).</p>", "question": "Simplify \\( \\dfrac{x^2 - 9}{x + 3} \\).", "options": ["\\( x - 3 \\)", "\\( x^2 - 3 \\)", "\\( x - 9 \\)", "\\( x + 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "Factorise the top as \\( (x+3)(x-3) \\), then cancel \\( (x+3) \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:misc:4465d21e', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( \\sqrt{12} + \\sqrt{27} = \\sqrt{39} \\)</p><p><strong>✅ The correct idea:</strong> You cannot add the numbers under the root. A weak answer writes \\( \\sqrt{39} \\); a strong answer simplifies to like surds: \\( 2\\sqrt{3} + 3\\sqrt{3} = 5\\sqrt{3} \\).</p>", "question": "\\( \\sqrt{12} + \\sqrt{27} = \\)", "options": ["\\( 5\\sqrt{3} \\)", "\\( \\sqrt{39} \\)", "\\( 6\\sqrt{3} \\)", "\\( \\sqrt{3} \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( 2\\sqrt{3} + 3\\sqrt{3} = 5\\sqrt{3} \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:misc:05185ea0', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Rationalising \\( \\dfrac{1}{2 + \\sqrt{3}} \\) by multiplying by \\( \\dfrac{2 + \\sqrt{3}}{2 + \\sqrt{3}} \\)</p><p><strong>✅ The correct idea:</strong> You must use the CONJUGATE (opposite sign). A weak answer keeps \\( 2 + \\sqrt{3} \\) and does not clear the surd; a strong answer multiplies by \\( 2 - \\sqrt{3} \\), giving denominator \\( 4 - 3 = 1 \\) and answer \\( 2 - \\sqrt{3} \\).</p>", "question": "Which multiplier rationalises \\( \\dfrac{1}{2 + \\sqrt{3}} \\)?", "options": ["\\( \\dfrac{2 - \\sqrt{3}}{2 - \\sqrt{3}} \\)", "\\( \\dfrac{2 + \\sqrt{3}}{2 + \\sqrt{3}} \\)", "\\( \\dfrac{\\sqrt{3}}{\\sqrt{3}} \\)", "\\( \\dfrac{1}{2 - \\sqrt{3}} \\)"]}'::jsonb, '{"answer": 0, "explain": "The conjugate \\( 2 - \\sqrt{3} \\) gives a rational denominator \\( 4 - 3 = 1 \\)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:tips:5e7c278a', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'tips', 'mcq', 1, '{"readingTitle": "explain — The ''exact'' command word", "reading": "<p><strong>0 marks:</strong> \\( 0.696 \\) as the answer to \\( \\frac{2}{5-\\sqrt{2}} + \\frac{1}{5+\\sqrt{2}} \\) — a decimal on an \"exact\" question.</p><p><strong>Full marks:</strong> \\( \\frac{15+\\sqrt{2}}{23} \\), the surd form. If unsure, write the exact form <em>and</em> the decimal — the exact form earns the marks and the decimal never loses them.</p>", "question": "On an ''exact'' surd question, which is safest?", "options": ["Give the surd form (optionally with the decimal)", "Give only the decimal", "Round to 3 s.f.", "Give only the decimal to 2 d.p."]}'::jsonb, '{"answer": 0, "explain": "The exact surd/fraction form is required; adding the decimal is harmless."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:tips:f8255ec9', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'tips', 'mcq', 1, '{"readingTitle": "tip — The rationalising ladder", "reading": "<p><strong>0 marks:</strong> jumping to a wrong denominator with no method.</p><p><strong>Partial:</strong> multiply by the conjugate but slip the sign to \\( 25 + 2 = 27 \\).</p><p><strong>Full marks:</strong> show \\( \\frac{2(5+\\sqrt{2}) + (5-\\sqrt{2})}{(5-\\sqrt{2})(5+\\sqrt{2})} \\), then \\( \\frac{15+\\sqrt{2}}{25 - 2} = \\frac{15+\\sqrt{2}}{23} \\). The unsimplified line is itself a mark.</p>", "question": "What is the correct denominator of \\( (5-\\sqrt{2})(5+\\sqrt{2}) \\)?", "options": ["\\( 23 \\)", "\\( 27 \\)", "\\( 25 \\)", "\\( 7 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( 25 - 2 = 23 \\) (difference of two squares)."}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:tips:bc216807', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'tips', 'mcq', 1, '{"readingTitle": "explain — ''Detailed reasoning'' means show every step", "reading": "<p>When a question says \"<em>In this question you must show detailed reasoning</em>\", the full method must appear. On 2023 Q4(b) the examiners required the <strong>unsimplified numerator over the common denominator</strong> to be seen before the tidy answer. A correct answer with no working — even from a calculator — scores <strong>zero</strong>.</p>", "question": "For a DR rationalising question, which step must be visible?", "options": ["The unsimplified numerator over the common denominator", "Only the final answer", "A decimal check", "The calculator display"]}'::jsonb, '{"answer": 0, "explain": "DR credits the visible method; the unsimplified common-denominator line is the required step."}'::jsonb),
